#!/usr/bin/env python
"""
Bootstrap: Substrate Anchor Adapter
Writes core/substrate_anchor.py + tests/test_substrate_anchor.py
Run: python bootstrap_substrate_anchor.py
"""
import base64, os, sys

if os.path.exists("core/universal_schema.py"): root = "."
elif os.path.exists("../core/universal_schema.py"): root = ".."
else: print("ERROR: Run from MABE root or one dir below."); sys.exit(1)

_p = os.path.join(root, "core/substrate_anchor.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

_p = os.path.join(root, "tests/test_substrate_anchor.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

print("Done. Run: python -m pytest tests/test_substrate_anchor.py -v")